import { GoogleGenAI, Part, Content } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const sendMessageStream = async (
  message: string,
  history: Content[],
  image?: string
) => {
  const chat = ai.chats.create({
    model: "gemini-3-pro-preview",
    history: history,
    config: {
      systemInstruction: `You are "QuantVision", a world-class financial analyst and quantitative researcher. 
      Your task is to analyze financial charts, tables, and documents with extreme precision.
      1. Technical Analysis: Identify candlestick patterns, indicators (RSI, MACD, Moving Averages), and support/resistance levels.
      2. Fundamental Extraction: Extract data from earnings reports or tables and perform calculations.
      3. Visual Thinking: Use Python code via codeExecution to perform quantitative verification, such as calculating CAGR, volatility, or plotting trend lines over visual data.
      4. Professionalism: Provide objective, data-driven insights. 
      Always state that your analysis is not financial advice.
      Do not refer to images in your response in markdown format. Use code execution to help with math or data visualization.`,
      tools: [{ codeExecution: {} }],
      thinkingConfig: {
        includeThoughts: true,
        thinkingBudget: 32768
      },
    },
  });

  const parts: Part[] = [{ text: message }];
  if (image) {
    const match = image.match(/^data:(.+);base64,(.+)$/);
    if (match) {
      let mimeType = match[1];
      if (mimeType === 'application/octet-stream') {
        mimeType = 'image/jpeg';
      }

      parts.push({
        inlineData: {
          mimeType: mimeType,
          data: match[2],
        },
      });
    }
  }

  const result = await chat.sendMessageStream({ message: parts });
  return result;
};

