                </div>
              )}
            </motion.div>
          ) : (
            messages.map((msg, index) => (
              <ChatMessageItem 
                key={msg.id} 
                message={msg} 
                isStreaming={isLoading && index === messages.length - 1}
              />
            ))
          )}
          <div ref={messagesEndRef} />
        </div>
      </div>

      {/* Input Area */}
      <div className="flex-shrink-0 p-4 pb-[calc(1rem+env(safe-area-inset-bottom))] bg-white/50 dark:bg-[#05070a]/50 backdrop-blur-xl border-t border-slate-200 dark:border-white/5 relative z-10">
        <div className="max-w-4xl mx-auto">
          <ChatInput onSend={handleSendMessage} disabled={isLoading} />
