import React, { useState, useRef, useEffect } from "react";
import { Send, Loader2, Image as ImageIcon, X, Link as LinkIcon } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

interface ChatInputProps {
  onSend: (message: string, image?: string) => void;
  disabled: boolean;
}

export const ChatInput: React.FC<ChatInputProps> = ({ onSend, disabled }) => {
  const [input, setInput] = useState("");
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [isUrlLoading, setIsUrlLoading] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if ((input.trim() || selectedImage) && !disabled) {
      onSend(input.trim(), selectedImage || undefined);
      setInput("");
      setSelectedImage(null);
      setErrorMessage(null);
      if (textareaRef.current) textareaRef.current.style.height = "auto";
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  // Xử lý dán (Paste)
  const handlePaste = async (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;

    // 1. Kiểm tra dán hình ảnh trực tiếp
    for (const item of items) {
      if (item.type.indexOf("image") !== -1) {
        const file = item.getAsFile();
        if (file) {
          const reader = new FileReader();
          reader.onload = (event) => setSelectedImage(event.target?.result as string);
          reader.readAsDataURL(file);
          return;
        }
      }
    }

    // 2. Kiểm tra dán URL hình ảnh
    const pastedText = e.clipboardData.getData("text");
    if (pastedText.match(/\.(jpeg|jpg|gif|png|webp)$/i) || pastedText.includes("unsplash.com") || pastedText.includes("tradingview.com/x/")) {
      e.preventDefault();
      setIsUrlLoading(true);
      try {
        const response = await fetch(pastedText, { mode: 'cors' });
        if (response.ok) {
          const blob = await response.blob();
          const reader = new FileReader();
          reader.onload = (event) => {
            setSelectedImage(event.target?.result as string);
            setIsUrlLoading(false);
          };
          reader.readAsDataURL(blob);
        } else {
          throw new Error("Cannot fetch image directly");
        }
      } catch (err) {
        // Nếu không fetch được do CORS, vẫn giữ text URL trong input
        setInput(pastedText);
        setErrorMessage("Lưu ý: Không thể tải ảnh trực tiếp từ URL này do bảo mật (CORS). Bạn nên chụp màn hình và dán (Ctrl+V).");
        setIsUrlLoading(false);
      }
    }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setSelectedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = "auto";
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [input]);

  return (
    <div className="relative group">
      <AnimatePresence>
        {selectedImage && (
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, scale: 0.9 }} className="absolute bottom-full mb-4 left-0">
            <div className="relative p-1 bg-white dark:bg-[#0f172a] rounded-xl border border-blue-500 shadow-2xl overflow-hidden">
              <img src={selectedImage} alt="Preview" className="h-32 w-auto rounded-lg object-contain bg-black" />
              <button onClick={() => setSelectedImage(null)} className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full hover:bg-rose-600 transition-colors">
                <X size={14} />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <form
        onSubmit={handleSubmit}
        className="relative flex items-end gap-2 bg-white dark:bg-[#0a0f18] p-2 rounded-2xl border border-slate-200 dark:border-white/10 shadow-2xl focus-within:border-emerald-500/50 transition-all duration-500"
      >
        <input type="file" ref={fileInputRef} onChange={handleFileSelect} accept="image/*" className="hidden" />

        <button
          type="button"
          onClick={() => fileInputRef.current?.click()}
          disabled={disabled || isUrlLoading}
          className="p-3 text-slate-400 hover:text-emerald-500 transition-all"
        >
          {isUrlLoading ? <Loader2 size={20} className="animate-spin" /> : <ImageIcon size={20} />}
        </button>

        <textarea
          ref={textareaRef}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          onPaste={handlePaste}
          placeholder="Phân tích gì hôm nay? (Dán ảnh Ctrl+V hoặc URL...)"
          disabled={disabled}
          rows={1}
          className="flex-1 max-h-[120px] min-h-[48px] py-3 px-2 bg-transparent border-none outline-none resize-none text-slate-800 dark:text-slate-100 placeholder-slate-500 disabled:opacity-50 font-medium text-sm md:text-base"
        />

        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          type="submit"
          disabled={(!input.trim() && !selectedImage) || disabled || isUrlLoading}
          className={`w-11 h-11 rounded-xl flex items-center justify-center transition-all ${
            (!input.trim() && !selectedImage) || disabled
              ? "bg-slate-100 dark:bg-slate-800 text-slate-400"
              : "bg-emerald-600 text-white shadow-lg shadow-emerald-500/20 hover:bg-emerald-700"
          }`}
        >
          {disabled ? <Loader2 className="animate-spin" size={18} /> : <Send size={18} />}
        </motion.button>
      </form>

      {errorMessage && (
        <div className="absolute top-full mt-2 left-0 right-0 text-[10px] text-rose-500 font-bold uppercase tracking-wider text-center">
          {errorMessage}
        </div>
      )}
    </div>
  );
};

